import{_ as t,o as s,c as r,ag as o}from"./chunks/framework.ETe_P6d1.js";const a="/kaiping-reports/assets/%E5%9B%BE1.CYVxG1i5.png",i="/kaiping-reports/assets/%E5%9B%BE2.CVddJg8r.png",e="/kaiping-reports/assets/%E5%9B%BE3.CIS3tAa9.png",n="/kaiping-reports/assets/%E5%9B%BE4.CZv-j_kF.png",_="/kaiping-reports/assets/%E5%9B%BE5.CSUMN_qh.png",g="/kaiping-reports/assets/%E5%9B%BE6.CmWhYsK1.png",c="/kaiping-reports/assets/%E5%9B%BE7.Dv6-qndX.png",l="/kaiping-reports/assets/%E5%9B%BE8.zhWUrRGD.png",m="/kaiping-reports/assets/%E5%9B%BE9.CaEtzllA.png",u="/kaiping-reports/assets/%E5%9B%BE10.BVESRbtS.png",E="/kaiping-reports/assets/%E5%9B%BE11.DCJhSQwE.png",B="/kaiping-reports/assets/%E5%9B%BE12.5NeiZifj.png",q="/kaiping-reports/assets/%E5%9B%BE13.QvjwYSff.png",h="/kaiping-reports/assets/%E5%9B%BE14.BINEvIaJ.png",k="/kaiping-reports/assets/%E5%9B%BE15.Vrg3nMIM.png",d="/kaiping-reports/assets/%E5%9B%BE16.oDoEyS_R.png",f="/kaiping-reports/assets/%E5%9B%BE17.D6Ydv-YO.png",C="/kaiping-reports/assets/%E5%9B%BE18.T8aCLsDj.png",b="/kaiping-reports/assets/%E5%9B%BE19.C6DzGaVk.png",x="/kaiping-reports/assets/%E5%9B%BE20.CWpHMj4R.png",S="/kaiping-reports/assets/%E5%9B%BE21.Bz2rwVbH.png",D="/kaiping-reports/assets/%E5%9B%BE22.CYDyTxh8.png",P="/kaiping-reports/assets/%E5%9B%BE23.BxdRwyuf.png",N="/kaiping-reports/assets/%E5%9B%BE24.1R4Zm94N.png",R="/kaiping-reports/assets/%E5%9B%BE25.CJHnuFMW.png",V="/kaiping-reports/assets/%E5%9B%BE26.dXX0SgxQ.png",T="/kaiping-reports/assets/%E5%9B%BE27.Cs-sX7p0.png",v="/kaiping-reports/assets/%E5%9B%BE28.DxAm2COx.png",W=JSON.parse('{"title":"材料表达与建造智慧：开平立园中西合璧营造体系研究","description":"","frontmatter":{},"headers":[],"relativePath":"reports/温雪滢/温雪滢-开平立园中西合璧营造体系研究.md","filePath":"reports/温雪滢/温雪滢-开平立园中西合璧营造体系研究.md"}'),I={name:"reports/温雪滢/温雪滢-开平立园中西合璧营造体系研究.md"};function w(A,p,J,M,Y,j){return s(),r("div",null,[...p[0]||(p[0]=[o('<h1 id="材料表达与建造智慧-开平立园中西合璧营造体系研究" tabindex="-1">材料表达与建造智慧：开平立园中西合璧营造体系研究 <a class="header-anchor" href="#材料表达与建造智慧-开平立园中西合璧营造体系研究" aria-label="Permalink to &quot;材料表达与建造智慧：开平立园中西合璧营造体系研究&quot;">​</a></h1><h1 id="一、引言-提出研究问题" tabindex="-1">一、引言：提出研究问题 <a class="header-anchor" href="#一、引言-提出研究问题" aria-label="Permalink to &quot;一、引言：提出研究问题&quot;">​</a></h1><p>开平立园作为&quot;开平碉楼与村落&quot;世界文化遗产的核心组成部分，是旅美华侨谢维立于1926-1936年历时十年营建的私家园林，是近代五邑侨乡中西文化碰撞、融合的标志性建筑遗存。在近代中国社会动荡、中西文化剧烈交汇的特殊历史语境下，立园既突破了岭南传统民居的营造范式，又未完全照搬西方建筑体系，形成了&quot;中魂西形、务实共生&quot;的独特营造逻辑。</p><p>本次调研以立园为核心对象，选取&quot;材料表达与建造智慧&quot;为核心专业主题，聚焦维度二&quot;建造材料与构造&quot;、维度三&quot;装饰符号与文化表达&quot;两大核心内容，从建筑材料的选择、构造工艺的创新、装饰符号的文化承载三个维度，深入剖析立园的营造体系，揭示其背后的侨乡生存需求、文化身份认同与建筑史价值，为近代侨乡建筑研究与文化遗产保护提供深度样本。</p><h1 id="二、案例分析-立园材料与构造的分层解析" tabindex="-1">二、案例分析：立园材料与构造的分层解析 <a class="header-anchor" href="#二、案例分析-立园材料与构造的分层解析" aria-label="Permalink to &quot;二、案例分析：立园材料与构造的分层解析&quot;">​</a></h1><p>（一）结构材料：现代技术与传统体系的融合创新</p><p>立园的结构体系是近代侨乡建筑技术转型的典型代表，其核心突破在于以钢筋混凝土框架结构替代传统砖木结构，实现了建筑安全性、耐久性与空间灵活性的全面提升。主体承重梁柱采用现浇钢筋混凝土工艺，通过钢筋与混凝土的协同受力，大幅提升了建筑的抗震、抗风与防御性能，适配多层碉楼、大跨度园林建筑的建造需求；填充墙体则以本土黏土青砖为核心，采用传统干砌/浆砌工艺，兼顾隔热、防潮与经济性，形成&quot;现代结构+传统围护&quot;的复合承重体系，既解决了传统砖木结构的安全隐患，又保留了岭南民居的地域适配性。</p><p>防御性构造是立园结构体系的核心特征，直接回应了近代开平&quot;四县不管、匪患猖獗&quot;的社会背景。乐天楼（保安更楼）作为园区的防御核心，墙体采用加厚防弹钢板加固，预留制式枪眼与封闭式瞭望口，可抵御土匪枪击与冲击；园区地下构建连通各主楼的混凝土衬砌逃生通道，通道采用钢筋混凝土现浇衬砌，坚固隐蔽，可在战乱、匪患发生时实现快速撤离，是华侨安全焦虑在建筑构造上的直接物质化表达。</p><p>（二）立面与细部材料：本土适配与全球供应链的协同</p><p>1/. 外墙饰面材料：水刷石与琉璃瓦的双重表达</p><p>立园外墙普遍采用水刷石（水洗石）抹灰工艺，以水泥混合花岗岩、大理石碎石骨料，通过高压水洗形成仿花岗岩质感，造价低廉且耐候性强，完美适配岭南多雨、暴晒、高湿的气候特征，成为民国时期侨乡建筑的标志性饰面工艺。门楼、柱式等重点装饰部位，采用预制水泥浮雕工艺，融合西式卷草、中式回纹、瑞兽纹样（如图1-5），实现了工业化预制生产与手工装饰艺术的结合，既提升了建造效率，又强化了建筑的装饰性与身份性。 <img src="'+a+'" alt="图1：瑞兽纹样灰塑"><img src="'+i+'" alt="图2：金属门环构件"><img src="'+e+'" alt="图3：融合卷草和瑞兽纹灰塑"><img src="'+n+'" alt="图4：融合卷草和回纹灰塑"><img src="'+_+'" alt="图5：天花彩绘菱形花卉纹"></p><p>屋顶则采用石湾窑绿釉琉璃瓦，以陶土胎为基底，施加绿釉烧制（如图6），传统中式歇山顶形制与西式立面形成鲜明的视觉对话（如图7），既满足了防雨、隔热的实用需求，又通过传统建筑符号强化了文化归属，实现了实用功能与文化表达的统一。 <img src="'+g+'" alt="图6：泮立楼中式歇山顶"><img src="'+c+'" alt="图7：神龛仿中式歇山顶装饰"> 2/. 门窗与花窗材料：传统工艺与现代审美结合</p><p>门窗体系以实木榫卯为核心框架，搭配彩色压花玻璃、磨砂玻璃，部分采用西式拱券带锁石结构，兼顾采光、通风与装饰性。镂空花窗采用两种核心工艺：一是预制混凝土花格，融合中式瑞兽、汉字与西式几何纹，通过模具预制实现批量生产（如图9-10）；二是石湾绿釉琉璃陶花格，以传统吉祥纹样为核心，通过预制构件嵌入墙体、砂浆填缝固定（如图8），实现了通透采光与装饰性的统一，既保留了传统岭南民居的通透布局，又融入了西方现代建筑的审美趣味。 <img src="'+l+'" alt="图8：石湾绿釉琉璃漏窗"><img src="'+m+'" alt="图9：西式拱券门与混凝土花格窗"><img src="'+u+'" alt="图10：铁艺窗花（西式几何纹）"> 3/. 地面与楼梯材料：水磨石与花砖的中西融合</p><p>室内地面核心采用意大利进口彩色水磨石与手工水泥花砖，水磨石以白水泥混合矿物色粉、大理石骨料现浇，耐磨防潮，纹样融合中式团寿、如意纹、回纹与西式几何纹（如图11-14），严格遵循中心对称布局，既符合中式风水&quot;藏风聚气&quot;的理念，又契合西方现代美学的对称原则，百年后仍光亮如新，成为立园材料工艺的标志性代表。楼梯为现浇混凝土踏步，面层水磨石处理（如图16），扶手采用硬木实木，通过金属预埋件与螺丝固定（如图15），兼顾了传统工艺的质感与现代结构的安全性，实现了传统木作与现代混凝土技术的完美融合。 <img src="'+E+'" alt="图11：水磨石地面海棠纹"><img src="'+B+'" alt="图12：水磨石地面菱形八角拼花"><img src="'+q+'" alt="图13：水磨石地面雪花纹"><img src="'+h+'" alt="图14：水磨石地面回纹与团寿纹"><img src="'+k+'" alt="图15：绿色水磨石扶手（现浇一体成型）"><img src="'+d+'" alt="图16：实木楼梯扶手与混凝土踏步"> 4/. 园林构筑物材料：预制工艺与传统石作的共生</p><p>花藤亭、打虎鞭、石桌石凳等园林构筑物，以钢筋混凝土预制与花岗岩雕刻为核心工艺，整体浇筑成型（如图17和19），结构稳固，可抵御台风与日晒雨淋；石桌石凳桌面采用彩色水磨石马赛克镶嵌，桌腿为花岗岩整块雕刻（如图18），既体现了现代材料的工业化优势，又保留了传统石作工艺的手工质感，是近代侨乡园林营造的典型代表。 <img src="'+f+'" alt="图17：亭式建筑混凝土镂空花格"><img src="'+C+'" alt="图18：花岗岩石桌石凳"><img src="'+b+'" alt="图19：西式柱头构件"> （三）装饰材料：符号承载与文化身份的锚定</p><p>立园的装饰材料以&quot;中魂西形&quot;为核心逻辑，以中式吉祥文化为内核，以西式建筑语言为载体，实现了文化根脉与海外视野的统一。</p><p>中式装饰材料：潮州金漆木雕、石湾彩釉陶、灰塑、壁画（如图20）等传统材料，以&quot;耕读传家、家族兴旺&quot;为核心主题，泮立楼内的潮州金漆木雕&quot;六国大封相&quot;&quot;张九龄点兵&quot;（如图21），寄托了家族多出人才、封侯拜相的期许；石湾窑彩釉陶瑞兽（如图22），以绿釉为主色调，搭配红、棕釉色，传统瑞兽造型，既起到装饰作用，又承载了镇宅祈福的文化内涵。 <img src="'+x+'" alt="图20：走廊彩绘梅树图案"><img src="'+S+'" alt="图21：潮州金漆木雕（六国大封相题材）"><img src="'+D+'" alt="图22：石湾窑彩釉陶瑞兽雕塑"> 西式装饰材料：科林斯柱式（如图23）、多立克柱式（如图24）、西式拱券（如图24）、巴洛克卷草纹等西式建筑符号，以预制水泥构件为载体，彰显了华侨的海外阅历与经济实力；室内设置英式壁炉（如图26）、西式银器陈设，花藤亭仿英国女王皇冠造型，以钢筋混凝土预制为工艺，是西方现代生活方式与审美趣味的直接体现。 <img src="'+P+'" alt="图23：科林斯柱式构件"><img src="'+N+'" alt="图24：西式拱券门廊"><img src="'+R+'" alt="图25：混合柱式构件"><img src="'+V+'" alt="图26：室内英式壁炉"> 水磨石与花砖装饰：水磨石地面融合中式吉祥纹与西式几何纹，色彩以红、黄、绿、白为主（如图27-28），分别寓意兴旺、尊贵、生机、稳重，形成&quot;足下生花、步步吉祥&quot;的效果，是中西装饰文化融合的最直观载体。 <img src="'+T+'" alt="图27：室外水磨石地面纹样"><img src="'+v+'" alt="图28：室内水磨石地面西式花卉纹"></p><h1 id="三、专业视角-建筑史与遗产保护理论下的深度解读" tabindex="-1">三、专业视角：建筑史与遗产保护理论下的深度解读 <a class="header-anchor" href="#三、专业视角-建筑史与遗产保护理论下的深度解读" aria-label="Permalink to &quot;三、专业视角：建筑史与遗产保护理论下的深度解读&quot;">​</a></h1><p>（一）建筑史视角：近代侨乡建筑的转型样本</p><p>立园的营造体系，是近代中国建筑转型期的典型代表，它既不是传统中式建筑的延续，也不是西式建筑的照搬，而是华侨基于自身生存需求、文化认同与审美趣味，创造出的&quot;侨乡建筑&quot;独特类型。</p><p>从建筑技术史来看，立园实现了现代工业技术在传统乡村的本土化实践：钢筋混凝土、水刷石、预制构件等现代建筑技术，与传统青砖、琉璃瓦、榫卯工艺深度融合，形成了适配侨乡需求的营造体系，打破了传统建筑的技术局限，为中国近代建筑史提供了民间实践的珍贵样本。</p><p>从建筑文化史来看，立园是中西文化从碰撞到融合的完整见证：其材料选择、构造工艺、装饰符号，完整呈现了华侨&quot;身在海外、根在中华&quot;的双重文化身份，既通过西式材料与符号彰显海外视野，又通过中式材料与符号锚定文化根脉，是近代中西文化交流的活化石。</p><p>（二）遗产保护视角：原真性保护的核心启示</p><p>立园作为世界文化遗产，其材料与构造的原真性，是其历史价值的核心载体，为文化遗产保护提供了重要启示：</p><p>1/. 保护需尊重材料与构造的原真性：立园的水刷石、水磨石、琉璃瓦等材料，以及现浇、预制、榫卯等工艺，是其历史信息的核心载体，保护中需避免过度改造、随意替换，保留历史痕迹与施工痕迹，如泮文楼仓库的弯曲铁皮、神龛的砂浆痕迹等，都是历史的见证。</p><p>2/. 保护需兼顾文化内涵的完整性：装饰材料背后的宗族、风水、情感等文化内涵，是立园的精神价值所在，保护不仅是修复建筑本体，更要传承其承载的文化记忆，如毓培别墅的纪念意义、&quot;打虎鞭&quot;的风水文化等。</p><p>3/. 保护需平衡利用与传承：立园作为世界文化遗产，需在保护的前提下合理利用，通过展示、研学等方式，让公众理解其建筑智慧与文化价值，实现文化遗产的活态传承。</p><p>（三）批判性思考：未完成建筑的历史反思</p><p>立园严格意义上是一座&quot;未完成的园林&quot;：1936年主楼主体完工，但规划中的家族书院、子弟学校、多处景观凉亭均未建成，1938年日军进犯广东、轰炸广州，谢维立全家被迫赴美避难，建设彻底中断。这座未完成的建筑本身，就是中国近代史的实物见证：它的兴建，依托于五邑华侨跨越太平洋的血汗积累；它的中断，源于抗日战争的全面爆发，侨汇中断、侨乡沦陷，华侨的家园理想被战争击碎；甚至后期建筑被日军劫掠、被外人霸占改造，&quot;四水归堂&quot;的天井被水泥封盖，都是近代中国社会动荡、侨产变迁的历史缩影。</p><p>这一历史语境提醒我们，文化遗产保护不仅是修复建筑本体，更要解读其背后的历史叙事，理解建筑作为历史见证的价值，避免将建筑从历史语境中剥离，实现&quot;修旧如旧&quot;与历史叙事传承的统一。</p><h1 id="四、调研结论" tabindex="-1">四、调研结论 <a class="header-anchor" href="#四、调研结论" aria-label="Permalink to &quot;四、调研结论&quot;">​</a></h1><p>本次调研通过对开平立园建造材料、构造工艺与装饰符号的深度分析，系统揭示了其&quot;中魂西形、务实共生&quot;的核心营造智慧：</p><p>在材料选择上，立园以实用主义为核心，本土材料与进口材料并用，传统工艺与现代技术并行，既解决了侨乡的安全、气候、运输等现实问题，又彰显了华侨的经济实力与国际视野；</p><p>在构造工艺上，立园以现代技术为支撑，创新形成了&quot;现代结构+传统围护&quot;的复合体系，适配侨乡的社会环境与自然环境，体现了极强的营造智慧；</p><p>在文化表达上，立园以中式文化为内核，以西式语言为载体，实现了双重文化身份的统一，是近代五邑华侨家国情怀、宗族观念、风水信仰、审美趣味的物质载体。</p><p>立园不仅是一座私家园林，更是近代中国中西文化融合、侨乡社会变迁、建筑技术转型的珍贵样本，其营造体系为研究近代中国建筑史、华侨史、中西文化交流史提供了不可替代的实物依据，也为当代建筑设计的地域性与创新性、文化遗产保护的原真性与活态传承提供了重要启示。</p><h1 id="五、附录" tabindex="-1">五、附录 <a class="header-anchor" href="#五、附录" aria-label="Permalink to &quot;五、附录&quot;">​</a></h1><p>（一）参考文献</p><ul><li>联合国教科文组织世界遗产中心. 开平碉楼与村落 /[EB/OL/]. UNESCO World Heritage Centre, 2007. <a href="https://whc.unesco.org/en/list/1112" target="_blank" rel="noreferrer">https://whc.unesco.org/en/list/1112</a></li><li>同济大学建筑与城市规划学院. 文化遗产保护研究 /[M/]. 北京：中国建筑工业出版社, 2010. ISBN：978-7-112-12014-7</li><li>张国雄. 开平碉楼与村落：华侨文化的世界遗产/[J/]. 东西问, 2021. （国务院侨务办公室官方发布）</li><li>广东省文物考古研究所、开平市文物局. 开平碉楼与村落保护管理规划 /[R/]. 2006.（官方申遗与保护正式文件）</li><li>五邑大学广东侨乡文化研究院. 开平侨乡建筑与华侨历史研究/[R/]. 地方高校重点研究基地成果, 2024.</li></ul><p>（二）附图说明</p><p>1/. 图1：瑞兽纹样灰塑</p><p>2/. 图2：金属门环构件</p><p>3/. 图3：融合卷草和瑞兽纹灰塑</p><p>4/. 图4：融合卷草和回纹灰塑</p><p>5/. 图5：天花彩绘菱形花卉纹</p><p>6/. 图6：泮立楼中式歇山顶</p><p>7/. 图7：神龛仿中式歇山顶装饰</p><p>8/. 图8：石湾绿釉琉璃漏窗</p><p>9/. 图9：西式拱券门与混凝土花格窗</p><p>10/. 图10：铁艺窗花（西式几何纹）</p><p>11/. 图11：水磨石地面海棠纹</p><p>12/. 图12：水磨石地面菱形八角拼花</p><p>13/. 图13：水磨石地面雪花纹</p><p>14/. 图14：水磨石地面回纹与团寿纹</p><p>15/. 图15：绿色水磨石扶手（现浇一体成型）</p><p>16/. 图16：实木楼梯扶手与混凝土踏步</p><p>17/. 图17：亭式建筑混凝土镂空花格</p><p>18/. 图18：花岗岩石桌石凳</p><p>19/. 图19：西式柱头构件</p><p>20/. 图20：走廊彩绘梅树图案</p><p>21/. 图21：潮州金漆木雕（六国大封相题材）</p><p>22/. 图22：石湾窑彩釉陶瑞兽雕塑</p><p>23/. 图23：科林斯柱式构件</p><p>24/. 图24：西式拱券门廊</p><p>25/. 图25：混合柱式构件</p><p>26/. 图26：室内英式壁炉</p><p>27/. 图27：室外水磨石地面纹样</p><p>28/. 图28：室内水磨石地面西式花卉纹</p>',68)])])}const z=t(I,[["render",w]]);export{W as __pageData,z as default};
